theorem theorem_2 (f D : ℝ → ℝ) (z_F : ℝ) (hf : ∀ z ∈ Set.Icc 0 z_F, 0 < f z)
    (hD : LipschitzContinuous D) :
    let H1_Df := { v : ℝ → ℝ | v ∈ L2_f(0, z_F) ∧ v_z_weak ∈ L2_D(0, z_F) }
    let norm_H1_Df (v : ℝ → ℝ) := Real.sqrt (∫ z in Set.Icc 0 z_F, f z * v z ^ 2 + ∫ z in Set.Icc 0 z_F, D z * (deriv v z) ^ 2)
    IsComplete H1_Df norm_H1_Df

theorem lemm_SD:SD (D : ℝ → ℝ) (hD_nonneg : ∀ z, D z ≥ 0) (hD_pos : ∀ z ∈ Set.Ico 0 1, D z > 0) :
  let S := fun (i j : Fin (n - 1)) => ∫ z in Set.Icc 0 1, D z * (deriv (fun x => x) z) * (deriv (fun x => x) z)
  let S_approx := fun (i j : Fin (n - 1)) => ∫ z in Set.Icc 0 1, D z * (deriv (fun x => x) z) * (deriv (fun x => x) z)
  (∀ i j, S i j = S j i) ∧
  (∀ y : Fin (n - 1) → ℝ, 0 < ∑ i, ∑ j, y i * y j * S i j) ∧
  (∀ y : Fin (n - 1) → ℝ, 0 < ∑ i, ∑ j, y i * y j * S_approx i j)
